import { useState, useEffect } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Row, 
  Text, 
  Divider, 
  MotionKeyframes, 
  useMotion,
  Badge,
  Box
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city?: string;
  temp?: number;
  condition?: string;
  conditionEmoji?: string;
  humidity?: number;
  windSpeed?: string;
  unit?: 'C' | 'F';
  forecast?: ForecastDay[];
}

export default function GeneratedComponent({
  city = "San Francisco",
  temp = 72,
  condition = "Partly Cloudy",
  conditionEmoji = "⛅",
  humidity = 65,
  windSpeed = "8 mph",
  unit = "F",
  forecast = [
    { day: "Mon", icon: "☀️", high: 75, low: 58 },
    { day: "Tue", icon: "⛅", high: 72, low: 56 },
    { day: "Wed", icon: "☁️", high: 68, low: 54 },
    { day: "Thu", icon: "🌧️", high: 62, low: 52 },
    { day: "Fri", icon: "☀️", high: 74, low: 57 },
  ]
}: Props) {
  const { motionEnabled } = useMotion();
  const [currentWeather, setCurrentWeather] = useState({
    city,
    temp,
    condition,
    conditionEmoji,
    humidity,
    windSpeed,
    unit,
    forecast
  });

  useEffect(() => {
    // Listen for real-time updates from the agent
    const handler = (e: any) => {
      if (e.detail) {
        setCurrentWeather(prev => ({ ...prev, ...e.detail }));
      }
    };

    // Using global scope listener for ggui bridge events
    addEventListener('ggui:agent-data', handler as EventListener);
    return () => removeEventListener('ggui:agent-data', handler as EventListener);
  }, []);

  const { city: dCity, temp: dTemp, condition: dCondition, conditionEmoji: dEmoji, humidity: dHumidity, windSpeed: dWind, unit: dUnit, forecast: dForecast } = currentWeather;

  return (
    <Container maxWidth="sm">
      <MotionKeyframes />
      <Card 
        padding={0} 
        style={{ 
          overflow: 'hidden',
          borderRadius: 'var(--ggui-shape-radius-xl, 16px)',
          border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
          animation: motionEnabled ? animation.fadeIn : 'none',
        }}
      >
        {/* Header Section - Branded Background */}
        <Box 
          padding="var(--ggui-spacing-6, 24px)"
          style={{ 
            background: 'linear-gradient(135deg, var(--ggui-color-primary-600, #0284c7), var(--ggui-color-primary-800, #075985))',
            color: '#ffffff',
          }}
        >
          <Stack gap={16}>
            <Row justify="between" align="center">
              <Stack gap={2}>
                <Text variant="h2" color="inherit" weight="bold">{dCity}</Text>
                <Text variant="body" color="rgba(255, 255, 255, 0.8)">{new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}</Text>
              </Stack>
              <Text style={{ fontSize: '48px' }} aria-hidden="true">{dEmoji}</Text>
            </Row>

            <Row align="center" gap={12}>
              <Text 
                style={{ 
                  fontSize: '48px', 
                  fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  lineHeight: 1
                }}
              >
                {dTemp}°{dUnit}
              </Text>
              <Badge variant="primary" style={{ backgroundColor: 'rgba(255, 255, 255, 0.2)', color: '#ffffff', border: 'none' }}>
                {dCondition}
              </Badge>
            </Row>
          </Stack>
        </Box>

        {/* Details Section */}
        <Box padding="var(--ggui-spacing-4, 16px)" background="var(--ggui-color-neutral-50, #f9fafb)">
          <Row justify="around" align="center">
            <Stack align="center" gap={4}>
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)" weight="medium">HUMIDITY</Text>
              <Text variant="body" weight="semibold" color="var(--ggui-color-neutral-900, #111827)">{dHumidity}%</Text>
            </Stack>
            <Divider orientation="vertical" margin={0} style={{ height: 24, borderColor: 'var(--ggui-color-neutral-200, #e5e7eb)' }} />
            <Stack align="center" gap={4}>
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)" weight="medium">WIND</Text>
              <Text variant="body" weight="semibold" color="var(--ggui-color-neutral-900, #111827)">{dWind}</Text>
            </Stack>
          </Row>
        </Box>

        <Divider margin={0} style={{ borderColor: 'var(--ggui-color-neutral-200, #e5e7eb)' }} />

        {/* Forecast Section */}
        <Box padding="var(--ggui-spacing-4, 16px)" background="var(--ggui-color-neutral-50, #f9fafb)">
          <Stack gap={12}>
            <Text variant="label" weight="semibold" color="var(--ggui-color-neutral-500, #6b7280)">5-DAY FORECAST</Text>
            <Row justify="between" align="center" style={{ width: '100%' }}>
              {dForecast.map((day, i) => (
                <Stack 
                  key={day.day} 
                  align="center" 
                  gap={4}
                  style={{ 
                    animation: motionEnabled ? animation.slideInUp : 'none',
                    animationDelay: (i * 100) + 'ms',
                    flex: 1
                  }}
                >
                  <Text variant="caption" weight="medium" color="var(--ggui-color-neutral-500, #6b7280)">{day.day}</Text>
                  <Text style={{ fontSize: '20px' }} aria-hidden="true">{day.icon}</Text>
                  <Stack gap={0} align="center">
                    <Text variant="caption" weight="bold" color="var(--ggui-color-neutral-900, #111827)">{day.high}°</Text>
                    <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">{day.low}°</Text>
                  </Stack>
                </Stack>
              ))}
            </Row>
          </Stack>
        </Box>
      </Card>
    </Container>
  );
}

import { Container, Card, Stack, Text, Divider, Row } from '@ggui-ai/design/primitives';
import React from 'react';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city?: string;
  temperature?: number;
  condition?: string;
  conditionIcon?: string;
  humidity?: number;
  windSpeed?: number;
  forecast?: ForecastDay[];
  onSubmit?: (data: unknown) => void;
}

export default function GeneratedComponent({
  city = "Unknown City",
  temperature = 0,
  condition = "Unknown",
  conditionIcon = "❓",
  humidity = 0,
  windSpeed = 0,
  forecast = [],
  onSubmit
}: Props) {
  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-4, 16px)" center>
      <Card
        padding="var(--ggui-spacing-6, 24px)"
        shadow="md"
        role="region"
        aria-label="Weather information"
        style={{
          borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
          backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
          border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)'
        }}
      >
        <Stack direction="vertical" gap="var(--ggui-spacing-4, 16px)">
          {/* Current Weather */}
          <Text
            variant="h2"
            align="center"
            style={{
              color: 'var(--ggui-color-primary-800, #075985)',
              fontWeight: 'var(--ggui-font-weight-bold, 700)'
            }}
          >
            {city}
          </Text>

          <Text
            align="center"
            style={{
              fontSize: 'var(--ggui-font-size-4xl, 36px)',
              fontWeight: 'var(--ggui-font-weight-bold, 700)',
              color: 'var(--ggui-color-primary-600, #0284c7)',
              marginTop: 'var(--ggui-spacing-2, 8px)'
            }}
          >
            {temperature}°C
          </Text>

          <Row justify="center" align="center" gap="var(--ggui-spacing-2, 8px)">
            <Text style={{ fontSize: 'var(--ggui-font-size-2xl, 24px)' }}>
              {conditionIcon}
            </Text>
            <Text
              style={{
                fontSize: 'var(--ggui-font-size-lg, 18px)',
                color: 'var(--ggui-color-neutral-700, #374151)'
              }}
            >
              {condition}
            </Text>
          </Row>

          <Row justify="center" gap="var(--ggui-spacing-4, 16px)" style={{ marginTop: 'var(--ggui-spacing-2, 8px)' }}>
            <Text style={{ color: 'var(--ggui-color-neutral-500, #6b7280)', fontSize: 'var(--ggui-font-size-sm, 14px)' }}>
              Humidity: {humidity}%
            </Text>
            <Text style={{ color: 'var(--ggui-color-neutral-500, #6b7280)', fontSize: 'var(--ggui-font-size-sm, 14px)' }}>
              Wind: {windSpeed} km/h
            </Text>
          </Row>

          <Divider margin="var(--ggui-spacing-6, 24px)" style={{ borderColor: 'var(--ggui-color-neutral-200, #e5e7eb)' }} />

          {/* 5-Day Forecast */}
          {forecast.length > 0 && (
            <Stack direction="horizontal" justify="around" align="center" gap="var(--ggui-spacing-2, 8px)" wrap>
              {forecast.map((dayForecast, index) => (
                <Stack key={index} direction="vertical" align="center" gap="var(--ggui-spacing-1, 4px)" style={{ minWidth: '80px' }}>
                  <Text
                    variant="caption"
                    align="center"
                    style={{
                      color: 'var(--ggui-color-neutral-700, #374151)',
                      fontWeight: 'var(--ggui-font-weight-medium, 500)'
                    }}
                  >
                    {dayForecast.day}
                  </Text>
                  <Text style={{ fontSize: 'var(--ggui-font-size-lg, 18px)' }}>
                    {dayForecast.icon}
                  </Text>
                  <Text
                    variant="caption"
                    align="center"
                    style={{
                      color: 'var(--ggui-color-neutral-500, #6b7280)',
                      whiteSpace: 'nowrap'
                    }}
                  >
                    {dayForecast.high}° / {dayForecast.low}°
                  </Text>
                </Stack>
              ))}
            </Stack>
          )}
        </Stack>
      </Card>
    </Container>
  );
}

import { useState, useEffect } from 'react';
import { Container, Card, Stack, Row, Text, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city?: string;
  country?: string;
  temperature?: number;
  condition?: string;
  humidity?: number;
  windSpeed?: number;
  unit?: 'C' | 'F';
  forecast?: ForecastDay[];
  onSubmit?: (data: unknown) => void;
}

export default function GeneratedComponent({
  city = 'San Francisco',
  country = 'USA',
  temperature = 72,
  condition = 'Partly Cloudy',
  humidity = 65,
  windSpeed = 12,
  unit = 'F',
  forecast = [
    { day: 'Mon', icon: '☀️', high: 75, low: 62 },
    { day: 'Tue', icon: '⛅', high: 73, low: 61 },
    { day: 'Wed', icon: '🌧️', high: 68, low: 58 },
    { day: 'Thu', icon: '☀️', high: 76, low: 63 },
    { day: 'Fri', icon: '⛅', high: 74, low: 60 },
  ],
  onSubmit,
}: Props) {
  const { motionEnabled } = useMotion();
  const [displayTemp, setDisplayTemp] = useState(temperature);

  // Animate temperature change
  useEffect(() => {
    const startTemp = displayTemp;
    const difference = temperature - startTemp;

    if (difference === 0) return;

    const steps = 20;
    const stepValue = difference / steps;
    let currentStep = 0;

    const interval = setInterval(() => {
      currentStep++;
      if (currentStep >= steps) {
        setDisplayTemp(temperature);
        clearInterval(interval);
        return;
      }
      setDisplayTemp(startTemp + stepValue * currentStep);
    }, 30);

    return () => clearInterval(interval);
  }, [temperature, displayTemp]);

  // Get weather icon emoji based on condition
  const getWeatherIcon = (cond: string): string => {
    const lower = cond.toLowerCase();
    if (lower.includes('sun') || lower.includes('clear')) return '☀️';
    if (lower.includes('cloud')) return '☁️';
    if (lower.includes('rain')) return '🌧️';
    if (lower.includes('snow')) return '❄️';
    if (lower.includes('storm') || lower.includes('thunder')) return '⛈️';
    if (lower.includes('wind')) return '💨';
    if (lower.includes('fog') || lower.includes('mist')) return '🌫️';
    if (lower.includes('partly')) return '⛅';
    return '🌤️';
  };

  // Calculate animation delay safely
  const getAnimationDelay = (index: number): string => {
    const delay = 200 + (index * 50);
    return delay.toString() + 'ms';
  };

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="md" padding="var(--ggui-spacing-4, 16px)">
        <Card
          padding="var(--ggui-spacing-6, 24px)"
          shadow="lg"
          style={{
            background: 'linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))',
            border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
            animation: motionEnabled ? animation.fadeIn : 'none',
          }}
        >
          <Stack direction="vertical" gap={24}>
            {/* Location Header */}
            <Stack direction="vertical" gap={4}>
              <Text
                variant="h2"
                weight="bold"
                color="var(--ggui-color-primary-900, #0c4a6e)"
              >
                {city}
              </Text>
              <Text
                variant="body"
                color="var(--ggui-color-primary-700, #0369a1)"
              >
                {country}
              </Text>
            </Stack>

            {/* Current Weather Section */}
            <Stack
              direction="vertical"
              gap={16}
              style={{
                backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
                padding: 'var(--ggui-spacing-6, 24px)',
                borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
              }}
            >
              {/* Temperature & Condition */}
              <Row
                gap={16}
                align="center"
                style={{
                  animation: motionEnabled ? animation.slideInUp : 'none',
                }}
              >
                <Text
                  variant="h1"
                  weight="bold"
                  color="var(--ggui-color-primary-900, #0c4a6e)"
                  style={{
                    fontSize: 'var(--ggui-font-size-4xl, 36px)',
                    lineHeight: '1',
                  }}
                >
                  {Math.round(displayTemp)}°
                </Text>

                <Stack direction="vertical" gap={4}>
                  <Text
                    style={{
                      fontSize: 'var(--ggui-font-size-3xl, 30px)',
                    }}
                  >
                    {getWeatherIcon(condition)}
                  </Text>
                  <Text
                    variant="body"
                    weight="semibold"
                    color="var(--ggui-color-primary-700, #0369a1)"
                  >
                    {condition}
                  </Text>
                </Stack>
              </Row>

              {/* Humidity & Wind Speed */}
              <Stack
                direction="horizontal"
                gap={16}
                justify="start"
                style={{
                  animation: motionEnabled ? animation.slideInUp : 'none',
                  animationDelay: '100ms',
                }}
              >
                {/* Humidity */}
                <Stack direction="vertical" gap={6}>
                  <Text
                    variant="caption"
                    color="var(--ggui-color-neutral-500, #6b7280)"
                    weight="semibold"
                  >
                    💧 Humidity
                  </Text>
                  <Text
                    variant="h3"
                    weight="semibold"
                    color="var(--ggui-color-primary-600, #0284c7)"
                  >
                    {humidity}%
                  </Text>
                </Stack>

                {/* Wind Speed */}
                <Stack direction="vertical" gap={6}>
                  <Text
                    variant="caption"
                    color="var(--ggui-color-neutral-500, #6b7280)"
                    weight="semibold"
                  >
                    💨 Wind Speed
                  </Text>
                  <Text
                    variant="h3"
                    weight="semibold"
                    color="var(--ggui-color-primary-600, #0284c7)"
                  >
                    {windSpeed} km/h
                  </Text>
                </Stack>
              </Stack>
            </Stack>

            {/* 5-Day Forecast */}
            <Stack direction="vertical" gap={12}>
              <Text
                variant="h3"
                weight="semibold"
                color="var(--ggui-color-primary-900, #0c4a6e)"
              >
                5-Day Forecast
              </Text>

              <Stack
                direction="horizontal"
                gap={12}
                wrap={true}
                style={{
                  overflowX: 'auto',
                  paddingBottom: 'var(--ggui-spacing-2, 8px)',
                }}
              >
                {forecast.map((day, index) => (
                  <Card
                    key={day.day}
                    padding="var(--ggui-spacing-4, 16px)"
                    shadow="sm"
                    style={{
                      minWidth: '100px',
                      textAlign: 'center',
                      backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
                      border: '1px solid var(--ggui-color-primary-300, #7dd3fc)',
                      animation: motionEnabled ? animation.slideInUp : 'none',
                      animationDelay: getAnimationDelay(index),
                      flex: '0 0 auto',
                    }}
                  >
                    <Stack direction="vertical" gap={8} align="center">
                      <Text
                        variant="label"
                        weight="semibold"
                        color="var(--ggui-color-primary-700, #0369a1)"
                      >
                        {day.day}
                      </Text>
                      <Text
                        style={{
                          fontSize: 'var(--ggui-font-size-2xl, 24px)',
                        }}
                      >
                        {day.icon}
                      </Text>
                      <Stack direction="horizontal" gap={4} justify="center">
                        <Text
                          variant="caption"
                          weight="bold"
                          color="var(--ggui-color-primary-600, #0284c7)"
                        >
                          {day.high}°
                        </Text>
                        <Text
                          variant="caption"
                          color="var(--ggui-color-neutral-500, #6b7280)"
                        >
                          {day.low}°
                        </Text>
                      </Stack>
                    </Stack>
                  </Card>
                ))}
              </Stack>
            </Stack>
          </Stack>
        </Card>
      </Container>
    </>
  );
}
